.darma-loader-darma-custom-135 {
  color: var(--loader-color, #0891b2);
width: 49px;
aspect-ratio: 1;
--c:no-repeat linear-gradient(135deg,currentColor,var(--loader-secondary-color, #22d3ee));
background: var(--c), var(--c), var(--c);
animation:
darma-loader-darma-custom-135-l15-1 1s infinite,
darma-loader-darma-custom-135-l15-2 1s infinite;
}
@keyframes darma-loader-darma-custom-135-l15-1 {
0%,100% {background-size:20% 100%}
33%,66% {background-size:20% 40%}
}
@keyframes darma-loader-darma-custom-135-l15-2 {
0%,33% {background-position: 0 0,50% 100%,100% 100%}
66%,100% {background-position: 100% 0,0 100%,50% 100%}
}

